type Cell = [number, number];

const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean =>
  (x1 !== x2 || y1 !== y2) &&
  Math.abs(x1 - x2) <= 1 &&
  Math.abs(y1 - y2) <= 1;

const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
  liveCells.filter((other) => isNeighbor(cell, other)).length;

const survives = (neighborCount: number): boolean =>
  neighborCount === 2 || neighborCount === 3;

export const nextGeneration = (liveCells: Cell[]): Cell[] =>
  liveCells.filter((cell) => survives(countLiveNeighbors(cell, liveCells)));
